using System.ComponentModel;
using System.Net;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Tools ---
var notepad = new Notepad();

var tools = new AITool[]
{
    AIFunctionFactory.Create(SearchWeb),
    AIFunctionFactory.Create(notepad.SaveNote),
    AIFunctionFactory.Create(notepad.GetNotes),
};

// --- Chat client (MEAI abstraction over OpenAI) ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research assistant. When given a topic you:
        1. Search the web for relevant information (make 2-3 searches with different queries).
        2. Save important findings as notes using the note-taking tool.
        3. After gathering enough information, retrieve all your notes and produce a
           well-structured summary with key points and sources.
        Be thorough but concise.
        """,
    name: "ResearchAgent",
    description: "Researches a topic by searching the web and summarizing findings.",
    tools: tools);

// --- Run ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent               ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.Write("\nEnter a research topic: ");
var topic = Console.ReadLine();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
});

var response = await agent.RunAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    options: runOptions);

Console.WriteLine("─── Research Summary ───────────────────\n");
Console.WriteLine(response.Text);

if (response.Usage is { } usage)
{
    Console.WriteLine($"\n─── Token usage: input={usage.InputTokenCount}, output={usage.OutputTokenCount} ───");
}

// --- Tool implementations ---

[Description("Search the web for information on a query. Returns a list of search result snippets.")]
static async Task<string> SearchWeb(
    [Description("The search query to look up on the web")] string query)
{
    Console.WriteLine($"  🔍 Searching: \"{query}\"");

    using var http = new HttpClient();
    http.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

    try
    {
        var encoded = WebUtility.UrlEncode(query);
        var url = $"https://en.wikipedia.org/w/api.php?action=query&list=search&srsearch={encoded}&utf8=&format=json&srlimit=4";
        var json = await http.GetStringAsync(url);
        return json;
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}";
    }
}

// --- Notepad helper class ---

sealed class Notepad
{
    private readonly List<string> _notes = [];

    [Description("Save a research note. Use this to record important findings from search results.")]
    public string SaveNote(
        [Description("The note content to save, including source attribution")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  📝 Note saved ({_notes.Count} total)");
        return $"Note saved. You now have {_notes.Count} note(s).";
    }

    [Description("Retrieve all saved research notes.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes saved yet.";
        }

        Console.WriteLine($"  📋 Retrieving {_notes.Count} note(s)");
        return string.Join("\n\n---\n\n", _notes.Select((n, i) => $"Note {i + 1}:\n{n}"));
    }
}

